def trimmed_mean(nums):
    if not nums:
        return None

    nums.sort()
    n = len(nums)
    mid = int((n - 1)/2)
    min_index, max_index = 0, n-1
    while min_index < mid or max_index > mid:
        if nums[min_index] == nums[0]:
            min_index += 1
        else:
            break
        if nums[max_index] == nums[-1]:
            max_index -= 1
        else:
            break
    return (sum(nums[min_index+1 : max_index]) + sum(nums[mid+1 : -1])) / (n-2)
